let Report={init(){RequestApi.fetch("/report/summary").then(t=>{t.success?this.processData(t.result):SnModal.error({title:"Algo salió mal",content:t.message})}).catch(t=>{SnModal.error({title:"Algo salió mal",content:t.message})})},processData(t){let e=document.getElementById("userCopy");if(e){let n="";[...t.userCopy].forEach(t=>{n+=`\n                            <div class="avatarList-item">\n                                <div class="SnAvatar" data-tooltip="${t.user_name}">\n                                    <span class="SnAvatar-counter">${t.count}</span>\n                                </div>\n                                <div class="avatarList-name">${t.user_name}</div>\n                            </div>`}),e.innerHTML=n}let n=document.getElementById("customerCopy");if(n){let e="";[...t.customerCopy].forEach(t=>{e+=`\n                            <div class="avatarList-item">\n                                <div class="SnAvatar" data-tooltip="${t.name}">\n                                    <span class="SnAvatar-counter">${t.count}</span>\n                                </div>\n                                <div class="avatarList-name">${t.name}</div>\n                            </div>`}),n.innerHTML=e}let a=document.getElementById("userCount");a&&(a.textContent=t.total.user);let s=document.getElementById("customerCount");s&&(s.textContent=t.total.customer);let o=document.getElementById("sessionCount");o&&(o.textContent=t.total.session)}};Report.init();